+    /// Execute a FK validation query with explicit stale-state invalidation.
+    ///
+    /// bd-issue59: This is a hardened query execution path for FK constraint
+    /// checking. After a prepared statement has been reused across multiple
+    /// executions within a write transaction (e.g., a BFS cycle-check loop),
+    /// the shared VDBE engine's cached state, the MemDatabase mirror, or
+    /// the ad-hoc prepared-statement reuse path can hold references that
+    /// cause subsequent FK validation SELECTs to return stale results
+    /// (empty result sets for rows that exist in the current transaction).
+    ///
+    /// The fix has two parts:
+    ///
+    /// 1. **Explicit memdb refresh**: force any pending in-transaction
+    ///    writes to be reflected in the MemDatabase mirror before the FK
+    ///    check query executes. Without this, the `query_with_params` path
+    ///    may read from a stale MemDatabase snapshot (especially on
+    ///    `:memory:` databases where reads can be serviced entirely from
+    ///    the MemDatabase without hitting the pager).
+    ///
+    /// 2. **Discard cached VDBE engine**: drop the cached engine entirely
+    ///    so the next execution allocates a fresh engine with no retained
+    ///    storage cursors, B-tree seek caches, or position stamps from
+    ///    prior operations. This eliminates any possibility of stale
+    ///    cursor state from a previous prepared-statement execution
+    ///    interfering with the FK validation read.
+    fn fk_validation_query(&self, sql: &str, params: &[SqliteValue]) -> Result<Vec<Row>> {
+        // Force any pending memdb writes to be visible before the FK check.
+        // This is critical after DML operations (INSERT/UPDATE/DELETE) that
+        // dirty the memdb within the same transaction. Without this,
+        // subsequent reads through the prepared-statement reuse path may
+        // see stale MemDatabase contents.
+        if self.memdb_requires_active_txn_reload.get()
+            || !self.pending_memdb_direct_upserts.borrow().is_empty()
+        {
+            let cx = self.op_cx_after_background_status();
+            self.refresh_memdb_from_active_txn_if_dirty(&cx)?;
+        }
+
+        // Discard any cached VDBE engine. This ensures the FK validation
+        // query creates a completely fresh engine with no retained cursor
+        // state from prior operations within this transaction. The cost is
+        // a single engine allocation (~21 collections) but this only fires
+        // when FK enforcement is active and a DML statement has dirtied
+        // the memdb, which is the exact scenario where stale state is
+        // dangerous.
+        *self.cached_vdbe_engine.borrow_mut() = None;
+
+        // Use the normal query path. The memdb refresh above ensures the
+        // MemDatabase reflects all in-transaction writes, and the engine
+        // discard ensures completely fresh execution context.
+        self.query_with_params(sql, params)
+    }
