+                "INSERT OR IGNORE INTO dependencies (issue_id, depends_on_id, type) VALUES ('node-45', 'node-1', 'blocks');",
+            )
+            .unwrap();
+            conn.execute(
+                "UPDATE issues SET updated_at = '2026-04-03T00:00:00Z' WHERE id = 'node-45';",
+            )
+            .unwrap();
+
+            // This must succeed — FK check must find 'node-45' in issues
+            let result = conn.execute(
+                "INSERT INTO events (issue_id, event_type) VALUES ('node-45', 'dep_added');",
+            );
+            assert!(
+                result.is_ok(),
+                "INSERT into events should succeed after many BFS iterations. Got error: {:?}",
+                result.err()
+            );
+
+            conn.execute("COMMIT;").unwrap();
+        }
+    }
+
+    /// Issue #59 variant: FK check on insert into child table should always
+    /// see parent rows that were present before the transaction began, even
+    /// after in-transaction writes dirty the memdb and force reloads.
+    /// Tests the critical `check_fk_parent_exists` -> `query_with_params`
+    /// -> prepared-reuse path specifically.
+    #[test]
+    fn test_issue59_direct_fk_check_query_sees_parent_after_dml() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("issue59_direct.db");
+        let db_str = db_path.to_string_lossy().to_string();
+
+        {
+            let conn = Connection::open(&db_str).unwrap();
+            conn.execute("PRAGMA foreign_keys = ON;").unwrap();
+            conn.execute("CREATE TABLE parent (id TEXT PRIMARY KEY, val TEXT);")
+                .unwrap();
+            conn.execute(
+                "CREATE TABLE child (
+                    id INTEGER PRIMARY KEY AUTOINCREMENT,
+                    parent_id TEXT NOT NULL,
+                    FOREIGN KEY (parent_id) REFERENCES parent(id)
+                );",
+            )
+            .unwrap();
+            conn.execute(
+                "CREATE TABLE other (
+                    id TEXT PRIMARY KEY,
+                    ref_id TEXT,
+                    FOREIGN KEY (ref_id) REFERENCES parent(id)
+                );",
+            )
+            .unwrap();
+            conn.execute("INSERT INTO parent VALUES ('p1', 'v1'), ('p2', 'v2'), ('p3', 'v3');")
+                .unwrap();
+        }
+
+        {
+            let conn = Connection::open(&db_str).unwrap();
+            conn.execute("PRAGMA foreign_keys = ON;").unwrap();
+            conn.execute("BEGIN IMMEDIATE;").unwrap();
+
+            // Prepare a statement and execute it many times to populate
+            // the prepared statement cache and VDBE engine state.
+            let stmt = conn
+                .prepare("SELECT id FROM parent WHERE id = ?1 UNION SELECT val FROM parent WHERE id = ?1")
+                .unwrap();
+            for _ in 0..20 {
+                let _ = stmt
+                    .query_with_params(&[SqliteValue::Text("p1".into())])
+                    .unwrap();
+                let _ = stmt
+                    .query_with_params(&[SqliteValue::Text("p2".into())])
+                    .unwrap();
+                let _ = stmt
+                    .query_with_params(&[SqliteValue::Text("p3".into())])
+                    .unwrap();
+            }
+            drop(stmt);
+
+            // Write operations that dirty the memdb
+            conn.execute("INSERT OR IGNORE INTO other VALUES ('o1', 'p1');")
+                .unwrap();
+            conn.execute("UPDATE parent SET val = 'updated' WHERE id = 'p1';")
+                .unwrap();
+
+            // Now verify the FK check path explicitly: query_with_params
+            // on the exact SQL that check_fk_parent_exists would generate.
+            let rows = conn
+                .query_with_params(
+                    "SELECT 1 FROM \"parent\" WHERE \"id\" = ?1 LIMIT 1",
+                    &[SqliteValue::Text("p1".into())],
+                )
+                .unwrap();
+            assert!(
+                !rows.is_empty(),
+                "FK validation query must find parent row 'p1' after DML"
+            );
+
+            // And the actual INSERT that triggers check_fk_parent_exists
+            let result = conn.execute("INSERT INTO child (parent_id) VALUES ('p1');");
+            assert!(
+                result.is_ok(),
+                "INSERT into child should succeed. Got error: {:?}",
+                result.err()
+            );
+
+            conn.execute("COMMIT;").unwrap();
+        }
+    }
